"""Load evaluation test cases from auto-generated cache.

Test cases are generated by RAGAS TestsetGenerator from the actual knowledge base
documents. Run POST /api/eval/generate first to create the cache, then
POST /api/eval/prepare to fill answers and contexts via the RAG + Agent pipeline.
"""

import logging

logger = logging.getLogger(__name__)


def load_test_cases() -> list[dict]:
    """Load test cases from the auto-generated cache file.

    Returns an empty list if no cache exists (call /api/eval/generate first).

    Returns:
        List of test case dicts with keys:
          - question (str)
          - ground_truth (str | None): reference answer from generator
          - reference_contexts (list[str]): chunks used to synthesize the question
          - category (str): evolution type from generation
          - difficulty (str): "auto"
          - answer (str): filled by prepare step
          - contexts (list[str]): filled by prepare step
    """
    from evaluation.dataset.generator import load_testset

    cases = load_testset()
    if not cases:
        logger.warning(
            "No cached test cases found. "
            "POST to /api/eval/generate to create a testset from the knowledge base."
        )
    return cases
